// GENERATED by derivations/materials/emit_material_golden.py — do not edit.
// Golden material tensors for the frequency-domain assembly.
//   (A) Uniaxial PML stretch  s_d = 1 - j·(u^n·δmax),  u = max(0, sign·(coord-inner)/t)
//   (B) Lossy dielectric      εr* = εr·(1 - j·tanδ) - j·σ/(ω·ε₀)
// Both pinned to the exact closed forms the Rust implements (e^{+jωt}).

use rapidfem_core::materials::{build_material_tensors, Dispersion, Material, PmlRegion};

fn rel_err(got: f64, want: f64) -> f64 {
    let scale = want.abs().max(1e-300);
    (got - want).abs() / scale
}

// ===== PML plus_x: dir=[1.0, 0.0, 0.0], inner=0.04, t=0.01, n=2.0, dmax=8.0 =====
#[test]
fn pml_stretch_matches_closed_form_plus_x() {
    let region = PmlRegion {
        tet_indices: vec![],
        er_base: 1.0,
        ur_base: 1.0,
        direction: [1.00000000000000000e+00, 0.00000000000000000e+00, 0.00000000000000000e+00],
        inner_face: 4.00000000000000008e-02,
        thickness: 1.00000000000000002e-02,
        exponent: 2.00000000000000000e+00,
        delta_max: 8.00000000000000000e+00,
    };
    // (x, y, z, sx_re, sx_im, sy_re, sy_im, sz_re, sz_im)
    let table: &[(f64, f64, f64, f64, f64, f64, f64, f64, f64)] = &[
        (2.99999999999999989e-02, 5.00000000000000000e-01, -2.99999999999999989e-01, 1.00000000000000000e+00, 0.00000000000000000e+00, 1.00000000000000000e+00, 0.00000000000000000e+00, 1.00000000000000000e+00, 0.00000000000000000e+00),
        (4.00000000000000008e-02, 0.00000000000000000e+00, 0.00000000000000000e+00, 1.00000000000000000e+00, 0.00000000000000000e+00, 1.00000000000000000e+00, 0.00000000000000000e+00, 1.00000000000000000e+00, 0.00000000000000000e+00),
        (4.25000000000000031e-02, 1.00000000000000000e+00, 2.00000000000000000e+00, 1.00000000000000000e+00, -5.00000000000000888e-01, 1.00000000000000000e+00, 0.00000000000000000e+00, 1.00000000000000000e+00, 0.00000000000000000e+00),
        (4.49999999999999983e-02, -1.00000000000000000e+00, 5.00000000000000000e-01, 1.00000000000000000e+00, -1.99999999999999778e+00, 1.00000000000000000e+00, 0.00000000000000000e+00, 1.00000000000000000e+00, 0.00000000000000000e+00),
        (5.00000000000000028e-02, 0.00000000000000000e+00, 0.00000000000000000e+00, 1.00000000000000000e+00, -8.00000000000000355e+00, 1.00000000000000000e+00, 0.00000000000000000e+00, 1.00000000000000000e+00, 0.00000000000000000e+00),
        (5.50000000000000003e-02, 0.00000000000000000e+00, 0.00000000000000000e+00, 1.00000000000000000e+00, -1.80000000000000000e+01, 1.00000000000000000e+00, 0.00000000000000000e+00, 1.00000000000000000e+00, 0.00000000000000000e+00),
    ];
    let mut max_err = 0.0_f64;
    for &(x, y, z, sx_re, sx_im, sy_re, sy_im, sz_re, sz_im) in table {
        let s = region.stretch(x, y, z);
        let want = [(sx_re, sx_im), (sy_re, sy_im), (sz_re, sz_im)];
        for k in 0..3 {
            let er = rel_err(s[k].re, want[k].0);
            let ei = rel_err(s[k].im, want[k].1);
            max_err = max_err.max(er).max(ei);
            assert!(er < 1e-12, "plus_x s[{}] re mismatch @ ({:.4e},{:.4e},{:.4e}): got {:.17e} want {:.17e} (rel {:.2e})", k, x, y, z, s[k].re, want[k].0, er);
            assert!(ei < 1e-12, "plus_x s[{}] im mismatch @ ({:.4e},{:.4e},{:.4e}): got {:.17e} want {:.17e} (rel {:.2e})", k, x, y, z, s[k].im, want[k].1, ei);
        }
    }
    eprintln!("pml plus_x: max rel err {:.2e}", max_err);
}

