// ===== dielectric fr4: er=4.4, tand=0.02, sigma=0.0, f=2400000000.0 =====
#[test]
fn lossy_dielectric_matches_closed_form_fr4() {
    let mat = Material {
        er: 4.40000000000000036e+00,
        ur: 1.0,
        tand: 2.00000000000000004e-02,
        cond: 0.00000000000000000e+00,
        tet_indices: vec![0],
        er_diag: None,
        ur_diag: None,
        dispersion: Dispersion::None,
    };
    let (er_t, _ur_t) = build_material_tensors(1, &[mat], 2.40000000000000000e+09);
    let want_re = 4.40000000000000036e+00;
    let want_im = -8.80000000000000088e-02;
    let mut max_err = 0.0_f64;
    // Isotropic: all three diagonal entries carry the same complex εr*.
    for k in 0..3 {
        let v = er_t[0][k][k];
        let er = rel_err(v.re, want_re);
        let ei = rel_err(v.im, want_im);
        max_err = max_err.max(er).max(ei);
        assert!(er < 1e-12, "fr4 εr* re mismatch [{}]: got {:.17e} want {:.17e} (rel {:.2e})", k, v.re, want_re, er);
        assert!(ei < 1e-12, "fr4 εr* im mismatch [{}]: got {:.17e} want {:.17e} (rel {:.2e})", k, v.im, want_im, ei);
    }
    eprintln!("dielectric fr4: max rel err {:.2e}", max_err);
}

